using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using verii_metivon_api.Modules.Accounting.Application.Services;namespace verii_metivon_api.Modules.Accounting.Api;[ApiController,Authorize,Route("api/accounting")]public sealed class AccountingController(IAccountingService s):ControllerBase{[HttpGet("accounts")]public async Task<IActionResult>Accounts([FromQuery]LedgerAccountQuery q,CancellationToken ct){var r=await s.GetAccountsAsync(q,ct);return StatusCode(r.StatusCode,r);}[HttpGet("journals")]public async Task<IActionResult>Journals([FromQuery]JournalQuery q,CancellationToken ct){var r=await s.GetJournalsAsync(q,ct);return StatusCode(r.StatusCode,r);}[HttpPost("accounts")]public async Task<IActionResult>Account(SaveLedgerAccountRequest x,CancellationToken ct){var r=await s.CreateAccountAsync(x,ct);return StatusCode(r.StatusCode,r);}[HttpPost("journals")]public async Task<IActionResult>Journal(CreateJournalRequest x,CancellationToken ct){var r=await s.CreateJournalAsync(x,ct);return StatusCode(r.StatusCode,r);}[HttpPost("journals/{id:long}/post")]public async Task<IActionResult>Post(long id,CancellationToken ct){var r=await s.PostJournalAsync(id,ct);return StatusCode(r.StatusCode,r);}}
